public DateTimeFormatters dateFormat(@Nullable String pattern) {
	if (isIso(pattern)) {
		this.dateFormatter = DateTimeFormatter.ISO_LOCAL_DATE;
		this.datePattern = "yyyy-MM-dd";
	}
	else {
		this.dateFormatter = formatter(pattern);
		this.datePattern = pattern;
	}
	return this;
}

private void registerJsr310(DateTimeFormatters dateTimeFormatters) {
	DateTimeFormatterRegistrar dateTime = new DateTimeFormatterRegistrar();
	configure(dateTimeFormatters::getDateFormatter, dateTime::setDateFormatter);
	configure(dateTimeFormatters::getTimeFormatter, dateTime::setTimeFormatter);
	configure(dateTimeFormatters::getDateTimeFormatter, dateTime::setDateTimeFormatter);
	dateTime.registerFormatters(this);
}

@Contract("_, _, !null -> !null")
	private @Nullable Boolean getEnabledProperty(ConfigurableEnvironment environment, String key,
			@Nullable Boolean defaultValue) {
		String name = "spring.web.resources.chain." + key + "enabled";
		if (defaultValue == null) {
			return environment.getProperty(name, Boolean.class);
		}
		return environment.getProperty(name, Boolean.class, defaultValue);
	}

private String[] appendSlashIfNecessary(String[] staticLocations) {
	String[] normalized = new String[staticLocations.length];
	for (int i = 0; i < staticLocations.length; i++) {
		String location = staticLocations[i];
		normalized[i] = location.endsWith("/") ? location : location + "/";
	}
	return normalized;
}

private CacheControl createCacheControl() {
	if (Boolean.TRUE.equals(this.noStore)) {
		return CacheControl.noStore();
	}
	if (Boolean.TRUE.equals(this.noCache)) {
		return CacheControl.noCache();
	}
	if (this.maxAge != null) {
		return CacheControl.maxAge(this.maxAge.getSeconds(), TimeUnit.SECONDS);
	}
	return CacheControl.empty();
}

@Override
	public void registerHints(RuntimeHints hints, @Nullable ClassLoader classLoader) {
		ClassLoader classLoaderToUse = (classLoader != null) ? classLoader : getClass().getClassLoader();
		String[] locations = DEFAULT_LOCATIONS.stream()
			.filter((candidate) -> classLoaderToUse.getResource(candidate) != null)
			.map((location) -> location + "**")
			.toArray(String[]::new);
		if (locations.length > 0) {
			hints.resources().registerPattern((hint) -> hint.includes(locations));
		}
	}

@Override
	protected void postProcessBeanFactory(ConfigurableListableBeanFactory beanFactory) {
		super.postProcessBeanFactory(beanFactory);
		if (!ObjectUtils.isEmpty(this.basePackages)) {
			this.scanner.scan(this.basePackages);
		}
		if (!this.annotatedClasses.isEmpty()) {
			this.reader.register(ClassUtils.toClassArray(this.annotatedClasses));
		}
	}

public static List<MessageSourceResolvable> wrapIfNecessary(List<? extends MessageSourceResolvable> errors) {
	if (CollectionUtils.isEmpty(errors)) {
		return Collections.emptyList();
	}
	List<MessageSourceResolvable> result = new ArrayList<>(errors.size());
	for (MessageSourceResolvable error : errors) {
		result.add(requiresWrapping(error) ? new Error(error) : error);
	}
	return List.copyOf(result);
}

@Override
	public boolean equals(Object obj) {
		if (this == obj) {
			return true;
		}
		if (obj == null) {
			return false;
		}
		if (obj instanceof ErrorPage other) {
			return ObjectUtils.nullSafeEquals(getExceptionName(), other.getExceptionName())
					&& ObjectUtils.nullSafeEquals(this.path, other.path) && this.status == other.status;
		}
		return false;
	}

@Override
	public int hashCode() {
		final int prime = 31;
		int result = 1;
		result = prime * result + ObjectUtils.nullSafeHashCode(getExceptionName());
		result = prime * result + ObjectUtils.nullSafeHashCode(this.path);
		result = prime * result + getStatusCode();
		return result;
	}

private Collection<ErrorPageRegistrar> getRegistrars() {
	if (this.registrars == null) {
		// Look up does not include the parent context
		this.registrars = new ArrayList<>(
				this.beanFactory.getBeansOfType(ErrorPageRegistrar.class, false, false).values());
		this.registrars.sort(AnnotationAwareOrderComparator.INSTANCE);
		this.registrars = Collections.unmodifiableList(this.registrars);
	}
	return this.registrars;
}

public EnumSet<DispatcherType> determineDispatcherTypes() {
	if (CollectionUtils.isEmpty(this.dispatcherTypes)) {
		T filter = getFilter();
		Assert.state(filter != null, "'filter' must not be null");
		if (ClassUtils.isPresent("org.springframework.web.filter.OncePerRequestFilter",
				filter.getClass().getClassLoader()) && filter instanceof OncePerRequestFilter) {
			return EnumSet.allOf(DispatcherType.class);
		}
		else {
			return EnumSet.of(DispatcherType.REQUEST);
		}
	}
	return EnumSet.copyOf(this.dispatcherTypes);
}

protected final String getOrDeduceName(@Nullable Object value) {
	if (this.name != null) {
		return this.name;
	}
	if (this.beanName != null) {
		return this.beanName;
	}
	if (value == null) {
		return "null";
	}
	return Conventions.getVariableName(value);
}

private void addServletContextInitializerBeans(ListableBeanFactory beanFactory) {
	for (Class<? extends ServletContextInitializer> initializerType : this.initializerTypes) {
		for (Entry<String, ? extends ServletContextInitializer> initializerBean : getOrderedBeansOfType(beanFactory,
				initializerType)) {
			addServletContextInitializerBean(initializerBean.getKey(), initializerBean.getValue(), beanFactory);
		}
	}
}

boolean contains(Class<?> type, Object object) {
	if (this.seen.isEmpty()) {
		return false;
	}
	// If it has been directly seen, or the implemented ServletContextInitializer
	// has been seen already
	if (type != ServletContextInitializer.class
			&& this.seen.getOrDefault(type, Collections.emptySet()).contains(object)) {
		return true;
	}
	return this.seen.getOrDefault(ServletContextInitializer.class, Collections.emptySet()).contains(object);
}

public ServletRegistrationBean(T servlet, boolean alwaysMapUrl, String... urlMappings) {
	Assert.notNull(servlet, "'servlet' must not be null");
	Assert.notNull(urlMappings, "'urlMappings' must not be null");
	this.servlet = servlet;
	this.alwaysMapUrl = alwaysMapUrl;
	this.urlMappings.addAll(Arrays.asList(urlMappings));
}

@Override
	protected void configure(ServletRegistration.Dynamic registration) {
		super.configure(registration);
		String[] urlMapping = StringUtils.toStringArray(this.urlMappings);
		if (urlMapping.length == 0 && this.alwaysMapUrl) {
			urlMapping = DEFAULT_MAPPINGS;
		}
		if (!ObjectUtils.isEmpty(urlMapping)) {
			registration.addMapping(urlMapping);
		}
		registration.setLoadOnStartup(this.loadOnStartup);
		if (this.multipartConfig != null) {
			registration.setMultipartConfig(this.multipartConfig);
		}
	}

private void handleException(HttpServletRequest request, HttpServletResponse response, ErrorWrapperResponse wrapped,
			Throwable ex) throws IOException, ServletException {
		Class<?> type = ex.getClass();
		String errorPath = getErrorPath(type);
		if (errorPath == null) {
			rethrow(ex);
			return;
		}
		if (response.isCommitted()) {
			handleCommittedResponse(request, ex);
			return;
		}
		forwardToErrorPage(errorPath, request, wrapped, ex);
	}

private boolean isClientAbortException(@Nullable Throwable ex) {
	if (ex == null) {
		return false;
	}
	for (Class<?> candidate : CLIENT_ABORT_EXCEPTIONS) {
		if (candidate.isInstance(ex)) {
			return true;
		}
	}
	return isClientAbortException(ex.getCause());
}

@Override
	public void addErrorPages(ErrorPage... errorPages) {
		for (ErrorPage errorPage : errorPages) {
			if (errorPage.isGlobal()) {
				this.global = errorPage.getPath();
			}
			else if (errorPage.getStatus() != null) {
				this.statuses.put(errorPage.getStatus().value(), errorPage.getPath());
			}
			else {
				this.exceptions.put(errorPage.getException(), errorPage.getPath());
			}
		}
	}

protected void deregisterJdbcDrivers(ServletContext servletContext) {
	for (Driver driver : Collections.list(DriverManager.getDrivers())) {
		if (driver.getClass().getClassLoader() == servletContext.getClassLoader()) {
			try {
				DriverManager.deregisterDriver(driver);
			}
			catch (SQLException ex) {
				// Continue
			}
		}
	}
}

@Contract("!null -> !null")
	protected @Nullable String customizePrefix(@Nullable String existingPrefix) {
		if (this.prefix == null) {
			return existingPrefix;
		}
		if (existingPrefix == null) {
			return this.prefix;
		}
		if (existingPrefix.startsWith(this.prefix)) {
			return existingPrefix;
		}
		return this.prefix + existingPrefix;
	}

@Override
	public void start() {
		if (!(this.parentContext instanceof WebServerApplicationContext)) {
			return;
		}
		ConfigurableApplicationContext managementContext = this.managementContext;
		if (managementContext == null) {
			managementContext = createManagementContext();
			registerBeans(managementContext);
			managementContext.refresh();
			this.managementContext = managementContext;
		}
		else {
			managementContext.start();
		}
	}

@Override
	public void stop() {
		ConfigurableApplicationContext managementContext = this.managementContext;
		if (managementContext != null) {
			if (this.parentContext.isClosed()) {
				managementContext.close();
			}
			else {
				managementContext.stop();
			}
		}
	}

private List<ManagementConfiguration> getConfigurations() {
	SimpleMetadataReaderFactory readerFactory = new SimpleMetadataReaderFactory(this.classLoader);
	List<ManagementConfiguration> configurations = new ArrayList<>();
	for (String className : loadFactoryNames()) {
		addConfiguration(readerFactory, configurations, className);
	}
	return configurations;
}

private int readOrder(AnnotationMetadata annotationMetadata) {
	Map<String, @Nullable Object> attributes = annotationMetadata
		.getAnnotationAttributes(Order.class.getName());
	Integer order = (attributes != null) ? (Integer) attributes.get("value") : null;
	return (order != null) ? order : Ordered.LOWEST_PRECEDENCE;
}

public static ManagementPortType get(Environment environment) {
	Integer managementPort = getPortProperty(environment, "management.server.");
	if (managementPort != null && managementPort < 0) {
		return DISABLED;
	}
	Integer serverPort = getPortProperty(environment, "server.");
	return ((managementPort == null || (serverPort == null && managementPort.equals(8080))
			|| (managementPort != 0 && managementPort.equals(serverPort))) ? SAME : DIFFERENT);
}

@Contract("!null -> !null")
	private @Nullable String cleanBasePath(@Nullable String basePath) {
		if (basePath == null) {
			return null;
		}
		String candidate = basePath.strip();
		if (StringUtils.hasText(candidate)) {
			if (!candidate.startsWith("/")) {
				candidate = "/" + candidate;
			}
			if (candidate.endsWith("/")) {
				candidate = candidate.substring(0, candidate.length() - 1);
			}
		}
		return candidate;
	}

private void customizeSameAsParentContext(T factory) {
	List<WebServerFactoryCustomizer<?>> customizers = new ArrayList<>();
	Assert.state(this.customizerClasses != null, "'customizerClasses' must not be null");
	for (Class<? extends WebServerFactoryCustomizer<?>> customizerClass : this.customizerClasses) {
		try {
			customizers.add(BeanFactoryUtils.beanOfTypeIncludingAncestors(this.beanFactory, customizerClass));
		}
		catch (NoSuchBeanDefinitionException ex) {
			// Ignore
		}
	}
	invokeCustomizers(factory, customizers);
}

protected void customize(T factory, ManagementServerProperties managementServerProperties,
			ServerProperties serverProperties) {
		Integer port = managementServerProperties.getPort();
		Assert.state(port != null, "'port' must not be null");
		factory.setPort(port);
		Ssl ssl = managementServerProperties.getSsl();
		if (ssl != null) {
			factory.setSsl(ssl);
		}
		factory.setServerHeader(serverProperties.getServerHeader());
		factory.setAddress(managementServerProperties.getAddress());
	}
